     1→/**
     2→ * MesoLayer (deck.gl) - DNA-like task block visualization
     3→ *
     4→ * Renders task blocks using SolidPolygonLayer for optimal performance.
     5→ * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
     6→ *
     7→ * Features:
     8→ * - SolidPolygonLayer for all task blocks
     9→ * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
    10→ * - Conflict indicators: red color on hasConflict tasks
    11→ * - Alternating row backgrounds for readability
    12→ * - Hover/selection/focus highlighting
    13→ *
    14→ * DECK-MIGRATE-002: Replaces R3F InstancedMesh-based MesoLayer
    15→ */
    16→
    17→import { SolidPolygonLayer } from '@deck.gl/layers';
    18→import type { TaskRender } from '../../data/types';
    19→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    20→
    21→// ─────────────────────────────────────────────────────────────
    22→// CONSTANTS
    23→// ─────────────────────────────────────────────────────────────
    24→
    25→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    26→
    27→// Task block height (with padding)
    28→const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
    29→const TASK_PADDING_Y = 2;
    30→
    31→// Color palette matching POC reference (as RGBA)
    32→const COLORS: Record<string, [number, number, number, number]> = {
    33→  blue: [59, 130, 246, 255],     // #3b82f6 - maintenance
    34→  orange: [245, 158, 11, 255],   // #f59e0b - overhaul
    35→  gray: [156, 163, 175, 255],    // #9ca3af - inspection
    36→};
    37→
    38→const CONFLICT_COLOR: [number, number, number, number] = [239, 68, 68, 255]; // #ef4444
    39→const SELECTION_COLOR: [number, number, number, number] = [6, 182, 212, 255]; // #06b6d4 cyan-500
    40→const FOCUS_COLOR: [number, number, number, number] = [139, 92, 246, 255]; // #8b5cf6 violet-500
    41→
    42→// Row background colors (alternating)
    43→const ROW_BG_EVEN: [number, number, number, number] = [255, 255, 255, 128]; // white 50%
    44→const ROW_BG_ODD: [number, number, number, number] = [248, 250, 252, 128]; // slate-50 50%
    45→
    46→// ─────────────────────────────────────────────────────────────
    47→// TYPES
    48→// ─────────────────────────────────────────────────────────────
    49→
    50→interface TaskPolygon {
    51→  id: string;
    52→  polygon: [number, number][];
    53→  task: TaskRender;
    54→}
    55→
    56→interface RowBackground {
    57→  trainIndex: number;
    58→  polygon: [number, number][];
    59→  isEven: boolean;
    60→}
    61→
    62→interface EffectPolygon {
    63→  taskId: string;
    64→  polygon: [number, number][];
    65→}
    66→
    67→// ─────────────────────────────────────────────────────────────
    68→// HELPER FUNCTIONS
    69→// ─────────────────────────────────────────────────────────────
    70→
    71→/**
    72→ * Brighten a color for hover effect
    73→ */
    74→function brightenColor(
    75→  color: [number, number, number, number],
    76→  factor: number
    77→): [number, number, number, number] {
    78→  return [
    79→    Math.min(255, Math.round(color[0] * factor)),
    80→    Math.min(255, Math.round(color[1] * factor)),
    81→    Math.min(255, Math.round(color[2] * factor)),
    82→    color[3],
    83→  ];
    84→}
    85→
    86→/**
    87→ * Apply opacity to a color
    88→ */
    89→function applyOpacity(
    90→  color: [number, number, number, number],
    91→  opacity: number
    92→): [number, number, number, number] {
    93→  return [color[0], color[1], color[2], Math.round(color[3] * opacity)];
    94→}
    95→
    96→/**
    97→ * Create a closed rectangle polygon from bounds
    98→ */
    99→function createRectPolygon(
   100→  x1: number,
   101→  y1: number,
   102→  x2: number,
   103→  y2: number
   104→): [number, number][] {
   105→  return [
   106→    [x1, y1],
   107→    [x2, y1],
   108→    [x2, y2],
   109→    [x1, y2],
   110→    [x1, y1], // Close the polygon
   111→  ];
   112→}
   113→
   114→// ─────────────────────────────────────────────────────────────
   115→// DATA GENERATION
   116→// ─────────────────────────────────────────────────────────────
   117→
   118→/**
   119→ * Generate row background polygons
   120→ */
   121→function generateRowBackgrounds(
   122→  trainCount: number,
